"""Compile a theory's constructs and propositions to lavaan model syntax.

The output is deterministic. Constructs with measurement indicators become a latent
measurement model (=~), and directed propositions become structural paths (~).
"""
from __future__ import annotations

import re

from .rigor import _as_list

_PATH = {"causes", "increases", "decreases", "mediates"}
_NON_ALNUM = re.compile(r"[^a-z0-9]+")


def _san(s) -> str:
    """Sanitise a measurement label into a syntactic lavaan variable name."""
    s = _NON_ALNUM.sub("_", str(s if s is not None else "").lower()).strip("_")
    return s or "x"


def _list(d: dict, key: str) -> list:
    v = d.get(key)
    return v if isinstance(v, list) else []


def compile_sem(T) -> str:
    T = T.data if hasattr(T, "data") else T
    out = [f"# lavaan model generated by theoryforge for {T.get('id', '')}", "# Measurement model"]
    for c in _list(T, "constructs"):
        meas = _as_list(c.get("measurement"))
        if meas:
            out.append(f"{c.get('id')} =~ " + " + ".join(_san(m) for m in meas))
    out.append("# Structural model")
    for p in _list(T, "propositions"):
        rel, frm, to = p.get("relation"), p.get("from"), p.get("to")
        if rel in _PATH:
            out.append(f"{to} ~ {frm}")
        elif rel == "associates":
            out.append(f"{frm} ~~ {to}")
        elif rel == "moderates":
            out.append(f"# moderation: {frm} moderates the path into {to} (specify interaction manually)")
    return "\n".join(out) + "\n"
